import React from "react";
import Navbar from "../components/Navbar";

function Home() {
  return (
    <div>
      <Navbar />

      <div style={{
        background:"#2a73cc",
        color:"white",
        padding:"80px",
        textAlign:"center"
      }}>
        <h1>Изучайте новые навыки онлайн</h1>
        <p>Найдите курсы по программированию, дизайну и технологиям</p>

        <input 
          placeholder="Поиск курсов..."
          style={{padding:"10px",width:"300px"}}
        />
      </div>
    </div>
  );
}

export default Home;
